create extension if not exists "pgcrypto";
create table if not exists public.players(id uuid primary key default gen_random_uuid(),scope text not null default 'scout' check(scope in('scout','team')),name text not null,birth_date date,age int default 0,position text not null default 'Stoper',club text default '',country text default '',nationality text default '',foot text default '',height text default '',contract_end date,matches int default 0,goals int default 0,assists int default 0,minutes int default 0,market_value text default '',salary text default '',scout_score numeric(3,1) default 0 check(scout_score>=0 and scout_score<=10),potential_score numeric(3,1) default 0 check(potential_score>=0 and potential_score<=10),stars int default 0 check(stars>=0 and stars<=5),tag text default 'Takip',favorite boolean default false,status text default 'Takip',photo_url text default '',report text default '',strengths text default '',weaknesses text default '',action_note text default '',video_url text default '',external_link text default '',created_by uuid references auth.users(id),created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.scout_reports(id uuid primary key default gen_random_uuid(),player_id uuid not null references public.players(id) on delete cascade,report_date date default current_date,scout_name text default '',score numeric(3,1) default 0 check(score>=0 and score<=10),note text default '',decision text default '',created_by uuid references auth.users(id),created_at timestamptz default now());
create table if not exists public.player_timeline(id uuid primary key default gen_random_uuid(),player_id uuid not null references public.players(id) on delete cascade,event_date date default current_date,title text not null,detail text default '',created_by uuid references auth.users(id),created_at timestamptz default now());
create table if not exists public.scouts(id uuid primary key default gen_random_uuid(),name text not null,region text default '',role text default 'Scout',assignment text default '',match_name text default '',player_name text default '',due_date date,status text default 'Bekliyor' check(status in('Bekliyor','İzleniyor','Tamamlandı')),reports_count int default 0,created_by uuid references auth.users(id),created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.agenda(id uuid primary key default gen_random_uuid(),plan_date date default current_date,title text not null,detail text default '',plan_type text default 'Plan',created_by uuid references auth.users(id),created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.transfer_pipeline(id uuid primary key default gen_random_uuid(),player_id uuid references public.players(id) on delete cascade,stage text default 'Takip',priority text default 'Normal',committee_note text default '',created_by uuid references auth.users(id),created_at timestamptz default now(),updated_at timestamptz default now());
alter table public.players enable row level security;alter table public.scout_reports enable row level security;alter table public.player_timeline enable row level security;alter table public.scouts enable row level security;alter table public.agenda enable row level security;alter table public.transfer_pipeline enable row level security;
drop policy if exists "players authenticated all" on public.players;create policy "players authenticated all" on public.players for all to authenticated using(true) with check(true);
drop policy if exists "reports authenticated all" on public.scout_reports;create policy "reports authenticated all" on public.scout_reports for all to authenticated using(true) with check(true);
drop policy if exists "timeline authenticated all" on public.player_timeline;create policy "timeline authenticated all" on public.player_timeline for all to authenticated using(true) with check(true);
drop policy if exists "scouts authenticated all" on public.scouts;create policy "scouts authenticated all" on public.scouts for all to authenticated using(true) with check(true);
drop policy if exists "agenda authenticated all" on public.agenda;create policy "agenda authenticated all" on public.agenda for all to authenticated using(true) with check(true);
drop policy if exists "pipeline authenticated all" on public.transfer_pipeline;create policy "pipeline authenticated all" on public.transfer_pipeline for all to authenticated using(true) with check(true);
insert into storage.buckets(id,name,public) values('player-images','player-images',true) on conflict(id) do update set public=true;
insert into storage.buckets(id,name,public) values('reports','reports',true) on conflict(id) do update set public=true;
drop policy if exists "player images public read" on storage.objects;create policy "player images public read" on storage.objects for select to public using(bucket_id='player-images');
drop policy if exists "player images authenticated upload" on storage.objects;create policy "player images authenticated upload" on storage.objects for insert to authenticated with check(bucket_id='player-images');
drop policy if exists "player images authenticated update" on storage.objects;create policy "player images authenticated update" on storage.objects for update to authenticated using(bucket_id='player-images') with check(bucket_id='player-images');
insert into public.players(scope,name,birth_date,age,position,club,country,nationality,foot,height,contract_end,matches,goals,assists,minutes,market_value,salary,scout_score,potential_score,stars,tag,favorite,status,report,strengths,weaknesses,action_note) values('scout','Marko Petrovic','2003-04-12',23,'Forvet','FK Novi','Sırbistan','Sırbistan','Sağ','1.86','2027-06-30',31,14,5,2410,'650K €','18K €/ay',8.4,8.7,5,'A Hedef',true,'Komite','Ceza sahası koşuları güçlü. İlk temas kalitesi iyi.','Bitiricilik, koşu zamanlaması, pres','Sırtı dönük oyun','Komiteye sun'),('team','Onur Baş','2003-01-01',23,'Stoper','Mevcut Takım','Türkiye','Türkiye','Sol','1.85','2027-06-30',0,0,0,0,'45','',8.5,8.8,4,'Hazır',false,'Takip','Mevcut takım oyuncusu performans takibi.','Savunma yerleşimi, temas, oyun disiplini','Uzun pas sürekliliği','Performans takibi');
